const ADJ = {};
for (const [k, v] of Object.entries(B.adj)) {
  ADJ[k] = v.split(",").map(s => {
    const [id, t] = s.includes(":") ? s.split(":") : [s, "M"];
    return { to: id, t };
  });
}
const DOTS = B.dots;
const DOT_MAP = {};DOTS.forEach(d=>{DOT_MAP[d.id]=d;});
const CITIES = DOTS.filter(d => d.t === "city");
const CW = B.cw, CH = B.ch;
const MAJOR_PASS_IDS = new Set(["b1","b12","b14","b16","b17","b19","b192","b193","b2","b21","b22","b23","b24","b26","b27","b3","b49","b5","b7","b8"]);
const MULTI_OCCUPANCY = new Set([
  ...CITIES.map(c=>c.id),
  ...DOTS.filter(d=>d.t==="major"||d.t==="special").map(d=>d.id),
  ...DOTS.filter(d=>d.t==="pass"&&MAJOR_PASS_IDS.has(d.id)).map(d=>d.id),
]); // cities + major dots + major-route passes + special = 227 double-occ dots

// Pre-compute static SVG layers (never change, render once)

const PASS_ALT = {}, PASS_NAMES = {}, PASS_REGIONS = {};
PASS_INFO.forEach(p => { PASS_ALT[p.id] = p.alt; PASS_NAMES[p.id] = p.name; PASS_REGIONS[p.id] = p.region; });
const REGIONS = [...new Set(PASS_INFO.map(p => p.region))].sort();

function getNodeName(id) { return B.cityNames[id] || PASS_NAMES[id] || id.replace(/^b/, "Dot "); }

// Short house label for logs: "Purushapura" not "House of Purushapura"
function houseName(players,idx){
  const p=players[idx];if(!p)return `H${Number(idx)+1}`;
  return p.name;
}

