// Spillover weight: power-1.5 decay — neighbors feel it, 27+ hops need huge dumps
function spilloverWeight(dist){return Math.pow(1/(1+dist/5),1.5);}

// Compute effective prices from base + effective supply level
function effectivePrice(base,effSupply){
  const ceil=Math.round(base*1.5);
  return Math.max(1,Math.min(ceil,base-Math.round(effSupply)));
}

